const t=[{id:"overview",label:"流程总览"},{id:"before-start",label:"报名前"},{id:"major-choice",label:"选专业"},{id:"register",label:"注册报考"},{id:"study",label:"备考考试"},{id:"graduation",label:"论文毕业"},{id:"faq",label:"常见问题"}],e=[{title:"先定地区",desc:"自考政策按省份执行。四川自考就优先看四川省教育考试院和主考院校通知。",tags:["四川自考","官方通知"]},{title:"再定路径",desc:"大自考成本低但靠自己，小自考有助学服务但费用更高。",tags:["大自考","小自考"]},{title:"重点看专业",desc:"专业决定难度、周期和用途。课程表比专业名称更重要。",tags:["课程计划","学位条件"]},{title:"按节点推进",desc:"注册、报考、考试、论文、毕业、学位，每一步都有时间窗口。",tags:["时间节点","流程管理"]}],s=[{title:"确定省份和用途",desc:"先确认在哪里考、学历用来做什么。",detail:"求职、考证、考研、考公、积分等用途不同，专业和学位要求也不同。"},{title:"选择路径",desc:"判断适合社会型还是应用型。",detail:"预算低、自律强可走社会型；时间紧、基础弱、需要提醒可了解应用型。"},{title:"筛选专业",desc:"看课程数量、是否考数学英语、实践课、论文和主考院校。",detail:"不要只看热门，先确认自己是否学得动、是否用得上。"},{title:"注册或报名",desc:"社会型按考试院注册，应用型要核实学校、助学点和费用合同。",detail:"这一步重点防信息不清、费用不明和包过宣传。"},{title:"报考科目",desc:"按当次开考安排选科目，新手不要一开始报太满。",detail:"建议先用 2-3 科测试节奏，难课和易课搭配。"},{title:"复习考试",desc:"教材打底，真题驱动，考前压缩背诵清单。",detail:"主观题要练关键词和答题结构，不要只停留在“看懂”。"},{title:"实践和论文",desc:"本科通常有论文，部分专业有实践课。",detail:"关注主考院校通知，错过申请窗口会影响毕业周期。"},{title:"毕业和学位",desc:"课程、实践、论文合格后申请毕业；需要学位证的本科生要单独规划。",detail:"学位可能看平均分、论文成绩、外语和申请期限。"}],i=[{title:"用途",items:["学历用来做什么","是否限制专业","是否必须拿学位证"]},{title:"基础",items:["每周能学几小时","英语数学是否薄弱","能否坚持半年以上"]},{title:"预算",items:["能否接受小自考费用","是否愿意自己查资料","周期变长能否接受"]}],a=[{title:"只想稳妥拿证",desc:"优先看课程结构简单、资料较多、统考压力可控的专业。",tips:["少数学","资料多","难度稳"]},{title:"为了职业发展",desc:"先看岗位、证书和行业要求，再倒推专业。",tips:["岗位匹配","考证要求","长期用途"]},{title:"为了考研考公",desc:"提前查目标院校或岗位要求，尤其是专业、学位和前置学历。",tips:["岗位表","院校要求","学位条件"]}],d=[{phase:"新生注册",what:"填写信息、上传照片、建立考籍",attention:"姓名、证件号、照片要仔细核对。"},{phase:"课程报考",what:"在规定时间选择当次考试科目并缴费",attention:"每次考试前都要单独报考，不是注册后自动安排。"},{phase:"准考证与考点",what:"考前查看考点、考场、座位和考试用品要求",attention:"提前规划路线，避免迟到。"}],o=[{situation:"第一次报考",suggestion:"2-3 科起步",reason:"先验证学习节奏和通过率。"},{situation:"上班族时间紧",suggestion:"1 门难课 + 1 门易课",reason:"难易搭配，压力更可控。"},{situation:"准备拿学位",suggestion:"从一开始关注平均分",reason:"不要只追求 60 分通过。"}],c=[{title:"看框架",desc:"先看目录、大纲和题型，知道这门课考什么。",points:["目录","大纲","题型"]},{title:"刷真题",desc:"用真题找高频考点，选择题重重复率，主观题重关键词。",points:["真题","错题","关键词"]},{title:"练输出",desc:"考前要能写出来，简答题和论述题要练答题结构。",points:["默写","限时","结构"]}],l=[{title:"实践课",desc:"部分专业有实践考核，按主考院校通知申请和参加。"},{title:"论文",desc:"本科通常要完成论文，注意申请时间、格式、查重和答辩。"},{title:"毕业申请",desc:"所有课程和环节合格后，在规定时间提交毕业申请。"},{title:"学位申请",desc:"需要学位证的本科生，要提前看平均分、论文、外语和申请期限。"}],n=[{title:"只问多久拿证",desc:"周期取决于课程、开考安排、通过率、论文和毕业窗口。"},{title:"只看专业名字",desc:"真正影响难度的是课程表，不是专业听起来热不热门。"},{title:"一次报太多科",desc:"新手先稳住通过率，比盲目追求速度更重要。"},{title:"忽略学位条件",desc:"本科要学位证，就不能等毕业前才看平均分和外语要求。"}],r=[{question:"新手第一步做什么？",answer:"先明确省份和用途，再看专业计划。不要第一步就只问哪个最快。"},{question:"一次报几科合适？",answer:"新手建议 2-3 科起步，上班族可以 1 门难课搭配 1 门易课。"},{question:"自考必须报机构吗？",answer:"不是。社会型可以自己完成；应用型适合需要助学服务和流程提醒的人。"},{question:"课程考完就自动毕业吗？",answer:"不会。课程、实践、论文等条件满足后，还要在规定时间申请毕业。"}],u=[{title:"论文不是最后随便补",desc:"论文通常有申请窗口、写作周期、导师修改、查重和答辩安排，错过节点会直接影响毕业。",tags:["时间窗口","毕业节点"]},{title:"选题决定后面难不难",desc:"题目不要太大、太空、太偏。能找到资料、能写出问题、能落到专业方向，才适合自考论文。",tags:["选题","资料可找"]},{title:"格式和原创性要提前管",desc:"目录、引用、参考文献、图表、查重都要按主考院校要求来，不要等提交前一天才改格式。",tags:["格式","查重"]}],g=[{title:"关注申请通知",desc:"课程接近考完时，就开始看主考院校论文申请条件、时间和材料。"},{title:"确定选题方向",desc:"围绕专业课程、工作经验或可查资料的现实问题确定题目。"},{title:"列提纲写初稿",desc:"先搭目录和论证框架，再补资料、案例和分析，避免边写边散。"},{title:"修改格式查重",desc:"按学校模板调整格式，检查引用、参考文献和重复率。"},{title:"准备答辩",desc:"熟悉选题意义、研究思路、主要内容、结论和论文不足。"}],p=[{title:"题目要小",desc:"不要写“某行业发展研究”这种大题，尽量缩到某个场景、群体、问题或案例。"},{title:"资料要够",desc:"选题前先搜资料。资料太少、数据拿不到、案例无法展开的题目，后面很痛苦。"},{title:"问题要清楚",desc:"论文不是资料拼贴，要能说清楚：发现什么问题、为什么出现、怎么改进。"},{title:"专业要贴合",desc:"题目要尽量贴近所学专业和主考院校要求，别写成完全无关的随笔。"}],w=[{part:"题目",focus:"范围清楚，最好包含研究对象、问题或场景",avoid:"题目过大、空泛、像宣传口号"},{part:"摘要",focus:"简要写研究目的、方法、内容和结论",avoid:"写成前言，或者只介绍背景不写结论"},{part:"目录",focus:"层级清楚，章节之间有逻辑推进",avoid:"标题重复、层级混乱、每章都像资料摘抄"},{part:"正文",focus:"先提出问题，再分析原因，最后给出对策或结论",avoid:"只堆概念、缺少分析、没有自己的表达"},{part:"参考文献",focus:"按学校格式整理，引用内容要能在正文中对应",avoid:"乱列文献、格式不统一、引用来源不规范"}],m=[{title:"提交初稿前",items:["题目是否过大，能不能进一步缩小","目录是否能体现问题、分析、对策","正文是否有自己的分析，不只是复制资料","参考文献是否与正文引用能对应"]},{title:"定稿提交前",items:["封面、目录、页眉页脚、字体行距是否符合模板","引用、脚注、参考文献格式是否统一","查重结果是否在学校要求范围内","导师修改意见是否逐条处理"]},{title:"答辩前",items:["能否用 2-3 分钟讲清论文写了什么","是否熟悉选题意义、研究方法和主要结论","是否准备好论文不足和改进方向","是否能解释目录中每一章的作用"]}],h=[{title:"为什么选这个题目？",desc:"回答时说清背景、现实意义和专业相关性，不要只说“好写”。"},{title:"论文主要解决什么问题？",desc:"把问题压缩成 1-2 句话，最好能对应正文中的章节安排。"},{title:"你的结论或建议是什么？",desc:"不要背大段正文，抓住核心结论和改进建议即可。"},{title:"论文还有什么不足？",desc:"可以从样本、资料、数据、研究深度等角度回答，态度要诚恳。"}],q=[{question:"自考论文什么时候开始准备？",answer:"建议最后几门课程时就关注主考院校通知。课程全部考完再看也可以，但容易错过申请窗口或准备时间不足。"},{question:"论文题目怎么选更稳？",answer:"选小一点、资料能找到、问题能说清、和专业相关的题目。不要一上来选过大的宏观题。"},{question:"论文查重是不是越低越好？",answer:"不是只看越低越好，更重要是符合学校要求，并且引用、参考文献和正文表达规范。具体标准以主考院校通知为准。"},{question:"答辩一般会问什么？",answer:"常见问题包括为什么选题、论文主要内容、研究方法、核心结论、创新点或不足。关键是熟悉自己的论文。"},{question:"可以找人代写论文吗？",answer:"不建议，也不应宣传或参与。这个页面只做流程、选题、格式和答辩准备建议，论文必须由本人独立完成。"}],C=[{title:"毕业证不是自动发",desc:"课程、实践、论文等环节都合格后，还要在规定时间提交毕业申请并通过审核。",tags:["主动申请","固定窗口"]},{title:"学位证不是毕业证附带",desc:"本科毕业后是否能拿学位，要看主考院校的平均分、论文、外语和申请期限等要求。",tags:["本科重点","单独申请"]},{title:"时间节点比想象中重要",desc:"毕业申请、论文申请、学位申请通常都有时间窗口，错过往往只能等下一批。",tags:["提前关注","别等通知"]}],b=[{title:"核对课程成绩",desc:"确认专业计划内课程、实践课、论文等是否全部合格。"},{title:"检查个人信息",desc:"姓名、证件号、照片、考籍信息、前置学历信息要保持一致。"},{title:"提交毕业申请",desc:"在当地考试院规定时间内提交申请，并按要求上传或提交材料。"},{title:"等待审核领证",desc:"审核通过后按通知领取毕业证；未通过要根据原因补材料或等下一批。"}],f=[{item:"作用",diploma:"证明你已经完成自考专业计划，取得对应学历层次。",degree:"证明本科阶段达到主考院校授予学位的标准。"},{item:"申请前提",diploma:"课程、实践、论文等毕业条件合格，并符合毕业审核要求。",degree:"通常要先满足本科毕业条件，同时达到平均分、论文、外语等要求。"},{item:"是否自动获得",diploma:"不是自动发，需要在规定时间提交毕业申请。",degree:"不是自动附带，通常要单独关注主考院校学位申请通知。"},{item:"最容易忽略",diploma:"前置学历、照片信息、免考转考、实践论文是否全部处理完。",degree:"平均分不够、论文成绩不达标、外语没完成、毕业后错过申请期限。"}],v=[{title:"毕业申请前",items:["所有课程成绩是否合格","实践课、论文是否已完成","本科前置学历是否可核验","专业计划内是否还有遗漏课程或替换课程"]},{title:"材料提交前",items:["身份证、准考证、照片信息是否一致","免考、转考、替换课程是否已处理","是否在官方申请时间内提交","系统里的联系电话和地址是否还能正常接收通知"]},{title:"领取毕业证后",items:["核对毕业证姓名、专业、层次信息","需要学位证的，立刻看主考院校申请通知","保存成绩单、毕业证扫描件和申请记录","确认学信网学历信息是否按期可查"]}],k=[{title:"最后 2-3 门课程时",desc:"开始看毕业申请条件和学位条件，尤其是本科前置学历、论文、平均分和外语要求。"},{title:"课程全部合格后",desc:"不要只等通知，主动核对实践课、论文、免考转考和毕业申请时间。"},{title:"毕业申请窗口内",desc:"按要求提交材料，保存提交记录。信息有误要尽快处理，不要拖到窗口结束。"},{title:"毕业证到手后",desc:"需要学位证的，马上关注主考院校学位申请；不需要学位的，也要保存好电子材料。"}],S=[{title:"平均分",desc:"很多院校会看课程平均分或指定课程成绩。准备拿学位的人，不要只按 60 分通过来规划。"},{title:"论文成绩",desc:"论文成绩可能影响学位申请。选题、格式、查重、答辩都要认真处理。"},{title:"外语要求",desc:"不同院校可能要求学位英语、英语成绩或其他外语替代条件，以主考院校通知为准。"},{title:"申请期限",desc:"学位通常有申请时间限制，毕业后不要拖太久，错过可能无法补申。"}],y=[{question:"课程全部考完，会自动毕业吗？",answer:"不会。自考毕业需要在规定时间主动申请，并通过考试院或相关部门审核。"},{question:"毕业证和学位证有什么区别？",answer:"毕业证证明学历层次完成；学位证证明本科阶段达到主考院校授予学位的要求。两者不是同一张证，也不是自动一起发。"},{question:"平均分会不会影响学位证？",answer:"可能会。不同主考院校要求不同，准备拿学位的人要尽早查清平均分或指定课程分数要求。"},{question:"论文成绩会不会影响学位证？",answer:"可能会。部分院校会要求论文成绩达到良好或指定标准，具体以主考院校当期通知为准。"},{question:"什么时候开始准备学位证最合适？",answer:"本科报名时就应该开始看。越早知道平均分、论文和外语要求，后面越不容易被动补救。"},{question:"毕业申请没通过怎么办？",answer:"先看未通过原因，常见是课程遗漏、实践论文未完成、前置学历或信息材料问题。按要求补齐后，一般需要等下一批申请窗口再提交。"},{question:"不申请学位证会影响毕业证吗？",answer:"通常不影响毕业证。毕业证和学位证是两个不同事项，但如果未来考研、考公、求职或评职称可能用到学位证，就建议提前争取。"}];export{e as a,i as b,n as c,s as d,o as e,r as f,l as g,g as h,p as i,m as j,h as k,w as l,a as m,q as n,C as o,t as p,b as q,d as r,c as s,u as t,v as u,k as v,S as w,f as x,y};
